SCSS="\n:host{display:block;width:100%;height:100dvh;min-height:0;overflow:hidden;--klax-primary:#7b0061;--klax-primary-2:#b00084;--klax-border:#cfd6df;--klax-panel:#f4f7fb;--klax-panel-2:#eef3f8;--klax-text:#27303b;--klax-muted:#637083;font-family:Arial,Helvetica,sans-serif}.embed-viewer{display:grid;grid-template-columns:minmax(0,1fr) 17.2rem;width:100%;height:100dvh;max-height:100dvh;overflow:hidden;background:#d8dee7}.map-wrap{position:relative;min-width:0;min-height:0;overflow:hidden}.map{width:100%;height:100%;min-height:0}.panel{display:grid;grid-template-rows:auto auto auto minmax(0,1fr) auto auto;min-width:0;min-height:0;max-height:100dvh;overflow:hidden;color:var(--klax-text);background:linear-gradient(180deg,var(--klax-panel),#edf2f7);border-left:1px solid #bfc8d3;box-shadow:-10px 0 22px rgba(15,23,42,.14)}.panel-header{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:.35rem;align-items:center;min-height:2.25rem;padding:.36rem .42rem .34rem;color:#fff;background:linear-gradient(180deg,var(--klax-primary-2),var(--klax-primary));border-bottom:1px solid rgba(0,0,0,.18)}.panel-header strong{display:block;font-size:.76rem;line-height:1.05;font-weight:800}.panel-header small{display:block;margin-top:.08rem;color:rgba(255,255,255,.78);font-size:.58rem;line-height:1}.section-title{display:grid;grid-template-columns:minmax(0,1fr) auto;align-items:center;gap:.25rem;min-height:1.35rem;padding:0 .42rem;background:#e7edf4;border-top:1px solid #d5dde7;border-bottom:1px solid #d5dde7}.section-title h3{margin:0;color:#344154;font-size:.62rem;font-weight:800;text-transform:uppercase;letter-spacing:.035em;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.section-title span{min-width:1.15rem;height:1.05rem;display:inline-grid;place-items:center;border-radius:999px;background:var(--klax-primary);color:#fff;font-size:.58rem;font-weight:800}.state{display:flex;align-items:center;gap:.35rem;margin:.35rem .42rem;padding:.38rem .45rem;border:1px solid #c7d2e0;border-radius:.35rem;background:#fff;color:#334155;font-size:.66rem;line-height:1.2}.state.error,.error-text{color:#991b1b;border-color:#fecaca;background:#fff1f2}.mini-loader{width:.75rem;height:.75rem;border-radius:999px;border:2px solid #cbd5e1;border-top-color:var(--klax-primary);animation:spin .7s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}.controls{display:grid;gap:.34rem;padding:.42rem;border-bottom:1px solid #d5dde7;background:var(--klax-panel-2)}label{display:grid;gap:.18rem;color:#344154;font-size:.6rem;font-weight:700}input,textarea,select{width:100%;min-width:0;border:1px solid #c8d2df;border-radius:.3rem;background:#fff;color:#1f2937;padding:.34rem .42rem;outline:none;font-size:.68rem;line-height:1.1}input:focus,textarea:focus,select:focus{border-color:var(--klax-primary);box-shadow:0 0 0 2px rgba(123,0,97,.12)}textarea{resize:vertical}.input-action{position:relative}.input-action span{position:absolute;right:.42rem;top:50%;transform:translateY(-50%);color:#64748b;font-size:.58rem;pointer-events:none;font-weight:800}.input-action input{padding-right:1.6rem;font-weight:800}.buttons{display:flex;flex-wrap:wrap;gap:.25rem}.buttons.compact{gap:.24rem}button{border:1px solid #b9c4d2;border-radius:.32rem;min-height:1.45rem;padding:.28rem .45rem;background:linear-gradient(180deg,#fff,#e9eef5);color:#263445;cursor:pointer;font-size:.62rem;font-weight:800;line-height:1;display:inline-flex;align-items:center;justify-content:center;gap:.22rem}button:hover:not(:disabled){border-color:var(--klax-primary);color:var(--klax-primary)}button:disabled{opacity:.42;cursor:not-allowed}button.primary{color:#fff;border-color:var(--klax-primary);background:linear-gradient(180deg,var(--klax-primary-2),var(--klax-primary))}button.ghost{background:rgba(255,255,255,.16);color:#fff;border-color:rgba(255,255,255,.42)}.icon-btn{width:1.35rem;height:1.35rem;min-height:1.35rem;padding:0;font-size:.8rem}.hint{margin:0;color:#64748b;font-size:.58rem;line-height:1.18}.items{display:grid;grid-template-rows:auto minmax(0,1fr);min-height:0;overflow:hidden}.items .section-title{position:sticky;top:0;z-index:3}.items-list{min-height:0;overflow-y:auto;overflow-x:hidden;padding:.32rem .34rem;display:grid;align-content:start;gap:.22rem}.empty-list{border:1px dashed #bdc7d4;border-radius:.35rem;padding:.55rem;color:#64748b;background:#fff;font-size:.64rem;text-align:center}.item-card{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:.22rem;align-items:center;min-height:2.22rem;padding:.18rem .18rem .18rem .22rem;border:1px solid #d3dbe6;border-radius:.32rem;background:#fff}.item-card:nth-child(even){background:#f9fbfd}.item-card.selected{border-color:var(--klax-primary);background:#fff5fb;box-shadow:inset 3px 0 0 var(--klax-primary)}.item-main{min-width:0;width:100%;border:0;border-radius:0;padding:0;min-height:auto;background:transparent;display:grid;grid-template-columns:auto minmax(0,1fr);justify-content:start;text-align:left;gap:.34rem}.item-main:hover:not(:disabled){color:inherit;border-color:transparent}.item-icon-mini{width:1.28rem;height:1.28rem;border-radius:.25rem;display:grid;place-items:center;color:#fff;font-size:.58rem;font-weight:900;border:1px solid rgba(15,23,42,.16);box-shadow:0 1px 2px rgba(15,23,42,.16)}.item-text{min-width:0;display:grid;gap:.02rem;line-height:1.05}.item-text strong{overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#1f2937;font-size:.64rem;font-weight:800}.item-text small{overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#64748b;font-size:.56rem;font-weight:700}.item-text em{color:#b45309;font-size:.56rem;font-style:normal;font-weight:900}.item-actions{display:flex;gap:.16rem}.item-actions button{width:1.42rem;height:1.42rem;min-height:1.42rem;padding:0;border-radius:.28rem;color:#334155}.item-actions button:hover{color:#fff;background:var(--klax-primary)}.selected-box,.tech-actions{display:grid;gap:.36rem;margin:0;border-top:1px solid #d5dde7;padding:.38rem .42rem;background:var(--klax-panel-2);max-height:11rem;overflow:auto}.selected-box p,.draft p,.selected-box dl{margin:0}.selected-box p{font-size:.62rem;color:#334155;line-height:1.16}.selected-box p strong{color:#111827}.selected-box dl{display:grid;gap:.18rem;margin:.28rem 0}.selected-box dl div{display:flex;justify-content:space-between;gap:.4rem;border-top:1px solid #d5dde7;padding-top:.2rem}.selected-box dt{color:#64748b;font-size:.56rem;font-weight:700}.selected-box dd{margin:0;color:#1f2937;font-size:.56rem;font-weight:800;text-align:right}.draft{display:grid;gap:.28rem;border:1px solid #d5dde7;border-radius:.35rem;padding:.36rem;background:#fff}.draft h4{margin:0;font-size:.68rem;color:var(--klax-primary)}.map-overlay{position:absolute;z-index:900;pointer-events:none}.map-overlay>*{pointer-events:auto}.map-overlay.top-left{left:.55rem;top:.55rem;display:grid;gap:.34rem}.map-overlay.top-right{right:.55rem;top:.55rem}.map-overlay select{width:10.5rem;min-height:1.65rem;padding:.34rem 1.8rem .34rem .52rem;color:#fff;background:rgba(15,23,42,.86);border-color:rgba(255,255,255,.28);box-shadow:0 8px 18px rgba(2,6,23,.28)}.origin-card,.route-card{display:flex;align-items:center;gap:.38rem;min-width:9.8rem;padding:.42rem .5rem;border-radius:.35rem;border:1px solid rgba(148,163,184,.28);background:rgba(15,23,42,.88);color:#fff;box-shadow:0 10px 22px rgba(2,6,23,.26);backdrop-filter:blur(8px)}.origin-card strong,.route-card strong{display:block;font-size:.62rem;line-height:1.05}.origin-card small,.route-card small{display:block;color:#cbd5e1;font-size:.54rem;line-height:1.1}.origin-dot{width:.62rem;height:.62rem;border-radius:999px;background:#3b82f6;box-shadow:0 0 0 3px rgba(59,130,246,.18),0 0 0 6px rgba(59,130,246,.08)}.route-card{display:grid;align-items:start}.route-card button{width:max-content;margin-top:.2rem;min-height:1.28rem;padding:.24rem .42rem;font-size:.56rem}.mapa-embed-origin-icon-host,.mapa-embed-element-icon-host,.mapa-embed-route-arrow-host,.mapa-div-icon,.mapa-element-label-host,.mapa-measure-label-host{background:transparent;border:0}.mapa-embed-origin-pin{position:absolute;left:50%;top:50%;width:2rem;height:2rem;border-radius:999px 999px 999px .35rem;transform:translate(-50%,-62%) rotate(-45deg);display:grid;place-items:center;background:linear-gradient(135deg,#2563eb,#38bdf8);border:3px solid #fff;box-shadow:0 0 0 4px rgba(37,99,235,.18),0 12px 22px rgba(2,6,23,.26)}.mapa-embed-origin-symbol{transform:rotate(45deg);font-size:.9rem}.mapa-embed-origin-pulse{position:absolute;inset:.32rem;border-radius:999px;background:rgba(59,130,246,.18);animation:originPulse 1.35s ease-out infinite}@keyframes originPulse{from{transform:scale(.62);opacity:.8}to{transform:scale(1.55);opacity:0}}.mapa-embed-origin-label{position:relative;transform:translate(-50%,-3rem);display:inline-flex;align-items:center;padding:.18rem .42rem;border-radius:999px;border:1px solid rgba(59,130,246,.22);background:rgba(239,246,255,.96);color:#1d4ed8;font-size:.58rem;font-weight:900;white-space:nowrap;box-shadow:0 8px 16px rgba(37,99,235,.14)}.mapa-point-icon-shell{display:flex;align-items:center;justify-content:center;transform-origin:center;transition:transform .18s ease,filter .18s ease,opacity .18s ease}.mapa-div-icon.is-selected .mapa-point-icon-shell,.mapa-embed-element-icon-host.is-selected .mapa-point-icon-shell{animation:mapa-selected-pulse 1.15s ease-in-out infinite;filter:drop-shadow(0 0 .5rem rgba(250,204,21,.82)) drop-shadow(0 0 1rem rgba(250,204,21,.42))}@keyframes mapa-selected-pulse{0%{transform:scale(1)}50%{transform:scale(1.18)}100%{transform:scale(1)}}.leaflet-tooltip.mapa-element-tooltip{border:1px solid rgba(148,163,184,.22);border-radius:999px;background:linear-gradient(180deg,rgba(15,23,42,.97),rgba(8,18,36,.95));color:#f8fafc;box-shadow:0 10px 22px rgba(2,6,23,.2),0 2px 8px rgba(2,6,23,.12);font-size:.58rem;font-weight:800;line-height:1;padding:.32rem .52rem;white-space:nowrap;max-width:14rem;overflow:hidden;text-overflow:ellipsis;pointer-events:none;text-align:center;backdrop-filter:blur(8px)}.leaflet-tooltip.mapa-element-tooltip:before{border-top-color:rgba(10,18,32,.96)}.mapa-element-label{position:relative;display:inline-flex;align-items:center;justify-content:center;max-width:12rem;padding:.04rem .1rem .2rem;border:1px solid rgba(148,163,184,.24);border-radius:999px;background:rgba(255,255,255,.94);color:#0f172a;font-size:.46rem;font-weight:800;line-height:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;box-shadow:0 8px 18px rgba(15,23,42,.1),0 2px 5px rgba(15,23,42,.06);backdrop-filter:blur(10px);transform:translate(-50%,calc(-100% - 8px));text-align:center;user-select:none;pointer-events:none;bottom:.2rem}.mapa-element-label.is-selected{border-color:rgba(37,99,235,.24);background:rgba(239,246,255,.96);color:#1d4ed8}.mapa-element-label:after{content:'';position:absolute;left:50%;bottom:-.22rem;width:.42rem;height:.42rem;background:rgba(255,255,255,.94);border-right:1px solid rgba(148,163,184,.18);border-bottom:1px solid rgba(148,163,184,.18);transform:translateX(-50%) rotate(45deg)}.mapa-element-label.is-selected:after{background:rgba(239,246,255,.96)}.mapa-embed-route-arrow{display:grid;place-items:center;width:1.6rem;height:1.6rem;border-radius:999px;background:rgba(123,0,97,.95);color:#fff;border:2px solid #fff;box-shadow:0 10px 20px rgba(2,6,23,.24);font-size:.9rem}.mapa-measure-label{display:inline-flex;align-items:center;justify-content:center;padding:.24rem .46rem;border-radius:999px;border:1px solid rgba(245,158,11,.4);background:rgba(8,18,36,.96);color:#fde68a;font-size:.64rem;font-weight:900;white-space:nowrap;box-shadow:0 8px 20px rgba(2,6,23,.32)}.mapa-embed-route-label{border-color:rgba(123,0,97,.36);color:#fce7f3}@media(max-width:920px){.embed-viewer{grid-template-columns:1fr;grid-template-rows:minmax(300px,48dvh) minmax(0,52dvh)}.panel{grid-template-rows:auto auto auto minmax(0,1fr) auto auto;border-left:0;border-top:1px solid #bfc8d3}}\n"
HTML='\n<div class="embed-viewer" [class.is-tecnico]="mode() === \'tecnico\'">\n  <main class="map-wrap">\n    <div #mapEl class="map"></div>\n    <div class="map-overlay top-left" *ngIf="origin()">\n      <div class="origin-card"><span class="origin-dot"></span><div><strong>Tu ubicación</strong><small>{{ origin()?.lat | number:\'1.6-6\' }}, {{ origin()?.lng | number:\'1.6-6\' }}</small></div></div>\n      <div class="route-card" *ngIf="routeTarget()"><strong>Ruta a {{ routeTarget()?.nombre }}</strong><small>{{ routeDistanceText() }}</small><button type="button" (click)="clearRoute()">Limpiar</button></div>\n    </div>\n    <div class="map-overlay top-right"><select [ngModel]="basemapKey()" (ngModelChange)="changeBasemap($event)"><option *ngFor="let option of basemapOptions" [ngValue]="option.key">{{ option.label }}</option></select></div>\n  </main>\n  <aside class="panel">\n    <header class="panel-header"><div><strong>{{ mode() === \'tecnico\' ? \'Mapa técnico\' : \'Mapa vendedor\' }}</strong><small *ngIf="context()">Empresa {{ context()?.company }} / {{ context()?.tenant }}</small></div><button type="button" class="icon-btn ghost" title="Cerrar" (click)="cancel()">×</button></header>\n    <section class="state" *ngIf="loading()"><span class="mini-loader"></span>Iniciando mapa...</section>\n    <section class="state error" *ngIf="!loading() && error()">{{ error() }}</section>\n    <section *ngIf="ready()" class="controls"><label>Radio<div class="input-action"><input type="number" min="1" [ngModel]="radioM()" (ngModelChange)="radioM.set(+$event || 1)" /><span>m</span></div></label><div class="buttons compact"><button type="button" class="primary" (click)="refreshNearby()" [disabled]="loadingItems()"><span class="pi pi-search"></span>Buscar</button><button type="button" (click)="centerOrigin()" [disabled]="!origin()"><span class="pi pi-crosshairs"></span>Centrar</button><button type="button" (click)="locateBrowser()"><span class="pi pi-map-marker"></span>GPS</button></div><p class="hint" *ngIf="loadingItems()">Buscando elementos cercanos...</p></section>\n    <section *ngIf="ready()" class="items"><div class="section-title"><h3>Elementos cercanos</h3><span>{{ items().length }}</span></div><div class="items-list"><div class="empty-list" *ngIf="!loadingItems() && !items().length">No hay elementos cercanos.</div><article class="item-card" *ngFor="let item of items()" [class.selected]="selected()?.idGeoElemento === item.idGeoElemento"><button type="button" class="item-main" (click)="focusItem(item, true)"><span class="item-icon-mini" [style.background]="item.colorFill || item.colorStroke || \'#7B0061\'" [style.border-color]="item.colorStroke || \'#7B0061\'"><span>{{ (item.tipoNombre || item.tipoCodigo || \'E\').slice(0, 1) }}</span></span><span class="item-text"><strong>{{ item.nombre }}</strong><small>{{ item.tipoNombre || item.tipoCodigo || \'Elemento\' }}</small><em *ngIf="item.distanciaM != null">{{ item.distanciaM | number:\'1.0-0\' }} m GPS</em></span></button><div class="item-actions"><button type="button" title="Trazar ruta" (click)="traceRoute(item)"><span class="pi pi-directions"></span></button><button type="button" title="Información" (click)="openInfo(item)"><span class="pi pi-info-circle"></span></button><button type="button" title="Usar" (click)="selected.set(item); selectForErp()"><span class="pi pi-check"></span></button></div></article></div></section>\n    <section *ngIf="selected() && infoOpen()" class="selected-box"><div class="section-title"><h3>Información</h3><button type="button" class="icon-btn" (click)="closeInfo()">×</button></div><p><strong>{{ selected()?.nombre }}</strong></p><p>{{ selected()?.tipoNombre || selected()?.tipoCodigo }}</p><p *ngIf="selected()?.descripcion">{{ selected()?.descripcion }}</p><dl><div><dt>Distancia</dt><dd>{{ selected()?.distanciaM != null ? (selected()?.distanciaM | number:\'1.0-0\') + \' m\' : \'N/D\' }}</dd></div><div><dt>Estado</dt><dd>{{ selected()?.estado || \'N/D\' }}</dd></div><div><dt>Código</dt><dd>{{ selected()?.codigo || selected()?.etiqueta || \'N/D\' }}</dd></div></dl><div class="buttons compact"><button type="button" class="primary" (click)="selectForErp()">{{ mode() === \'tecnico\' ? \'Usar caja\' : \'Usar\' }}</button><button type="button" (click)="traceRoute(selected()!)">Ruta</button></div></section>\n    <section *ngIf="mode() === \'tecnico\' && ready()" class="tech-actions"><div class="section-title"><h3>Trabajo técnico</h3></div><div class="buttons compact"><button type="button" (click)="startCreateBox()" [disabled]="!can(\'puedeCrearCaja\') || !actionEnabled(\'create_box\')"><span class="pi pi-plus-circle"></span>Caja</button><button type="button" (click)="startDrawFiber()" [disabled]="!can(\'puedeCrearFibra\') || !actionEnabled(\'draw_fiber\')"><span class="pi pi-share-alt"></span>Fibra</button></div><div class="draft" *ngIf="draftMode() !== \'none\'"><h4>{{ draftMode() === \'box\' ? \'Nueva caja\' : \'Nuevo tendido\' }}</h4><p class="hint">Click en el mapa para marcar puntos.</p><label>idRedNodoFk<input type="number" [(ngModel)]="createForm.idRedNodoFk" /></label><label>idGeoTipoElementoFk<input type="number" [(ngModel)]="createForm.idGeoTipoElementoFk" /></label><label>Nombre<input type="text" [(ngModel)]="createForm.nombre" /></label><label>Descripción<textarea rows="2" [(ngModel)]="createForm.descripcion"></textarea></label><p class="hint">Puntos: {{ draftPoints().length }}</p><p class="error-text" *ngIf="createError()">{{ createError() }}</p><div class="buttons compact"><button type="button" (click)="useOriginAsDraftPoint()" [disabled]="!origin()">Origen</button><button type="button" (click)="undoDraftPoint()" [disabled]="!draftPoints().length">Deshacer</button><button type="button" class="primary" (click)="saveDraft()" [disabled]="saving()">{{ saving() ? \'Guardando...\' : \'Guardar\' }}</button><button type="button" (click)="clearDraft()">Cancelar</button></div></div></section>\n  </aside>\n</div>\n'
METHOD='\n  private createElementIcon(item: MapaElementoCercano, style: ElementVisualStyle, selected = false): L.DivIcon {\n    const source = String(item.iconoFuente || \'\').trim().toLowerCase();\n    const iconValue = String(item.icono || \'\').trim();\n    const iconClassValue = String(item.iconoClase || \'\').trim();\n    const size = Math.round(style.size);\n    const stroke = style.stroke;\n    const fill = style.fill;\n    const textColor = style.text || stroke;\n    const selectedClass = selected ? \' is-selected\' : \'\';\n    if (this.isUrlIcon(source, iconValue)) return L.divIcon({ className: `mapa-div-icon mapa-embed-element-icon-host${selectedClass}`, html: `<div class="mapa-point-icon-shell" style="width:${size}px;height:${size}px;"><img src="${this.escapeHtml(iconValue)}" alt="" style="width:${size}px;height:${size}px;display:block;" /></div>`, iconSize: [size, size], iconAnchor: [Math.round(size / 2), Math.round(size / 2)] });\n    if (this.isMaterialSymbol(source)) { const familyClass = this.resolveMaterialFamily(source); const glyph = this.escapeHtml(iconValue || \'radio_button_checked\'); const weightAxis = Math.max(100, Math.min(700, Math.round((style.weight || 3) * 120))); const fillAxis = fill && fill !== \'transparent\' ? 1 : 0; return L.divIcon({ className: `mapa-div-icon mapa-embed-element-icon-host${selectedClass}`, html: `<div class="mapa-point-icon-shell" style="width:${size}px;height:${size}px;color:${textColor};"><span class="${familyClass}" style="font-size:${size}px;line-height:1;font-variation-settings:\'FILL\' ${fillAxis}, \'wght\' ${weightAxis}, \'GRAD\' 0, \'opsz\' ${Math.max(20, size)};">${glyph}</span></div>`, iconSize: [size, size], iconAnchor: [Math.round(size / 2), Math.round(size / 2)] }); }\n    const cssClass = iconClassValue || (iconValue.includes(\'pi-\') ? iconValue : \'\');\n    if (this.isCssClassIcon(source, cssClass)) { const classValue = this.escapeHtml(cssClass.startsWith(\'pi \') ? cssClass : cssClass); return L.divIcon({ className: `mapa-div-icon mapa-embed-element-icon-host${selectedClass}`, html: `<div class="mapa-point-icon-shell" style="width:${size}px;height:${size}px;color:${textColor};font-size:${size}px;line-height:1;"><i class="${classValue}"></i></div>`, iconSize: [size, size], iconAnchor: [Math.round(size / 2), Math.round(size / 2)] }); }\n    if (source.includes(\'triangle\')) { const half = Math.max(6, Math.round(size * 0.5)); return L.divIcon({ className: `mapa-div-icon mapa-embed-element-icon-host${selectedClass}`, html: `<div class="mapa-point-icon-shell" style="width:${size}px;height:${size}px;display:flex;align-items:center;justify-content:center;"><div style="width:0;height:0;border-left:${half}px solid transparent;border-right:${half}px solid transparent;border-bottom:${size}px solid ${fill};filter:drop-shadow(0 0 1px ${stroke});"></div></div>`, iconSize: [size, size], iconAnchor: [Math.round(size / 2), Math.round(size * 0.85)] }); }\n    if (source.includes(\'target\')) { const border = Math.max(2, Math.round(style.weight || 2)); const inner = Math.max(2, Math.round(size * 0.18)); return L.divIcon({ className: `mapa-div-icon mapa-embed-element-icon-host${selectedClass}`, html: `<div class="mapa-point-icon-shell" style="width:${size}px;height:${size}px;border:${border}px solid ${stroke};border-radius:999px;background:${fill};box-shadow:inset 0 0 0 ${inner}px white;"></div>`, iconSize: [size, size], iconAnchor: [Math.round(size / 2), Math.round(size / 2)] }); }\n    if (source.includes(\'donut\')) { const border = Math.max(3, Math.round(size * 0.22)); return L.divIcon({ className: `mapa-div-icon mapa-embed-element-icon-host${selectedClass}`, html: `<div class="mapa-point-icon-shell" style="width:${size}px;height:${size}px;border:${border}px solid ${stroke};border-radius:999px;background:transparent;"></div>`, iconSize: [size, size], iconAnchor: [Math.round(size / 2), Math.round(size / 2)] }); }\n    const border = Math.max(2, Math.round(style.weight || 2)); return L.divIcon({ className: `mapa-div-icon mapa-embed-element-icon-host${selectedClass}`, html: `<div class="mapa-point-icon-shell" style="width:${size}px;height:${size}px;border-radius:999px;background:${fill};border:${border}px solid ${stroke};box-shadow:0 0 0 1px rgba(255,255,255,.8);"></div>`, iconSize: [size, size], iconAnchor: [Math.round(size / 2), Math.round(size / 2)] });\n  }\n'
