def backup(path:Path):
    if path.exists():
        b=path.with_suffix(path.suffix+'.bak_compact_embed_'+datetime.now().strftime('%Y%m%d_%H%M%S'))
        shutil.copy2(path,b); print('backup:',b)
def replace_method(text,name,replacement):
    idx=text.find(f'  private {name}(')
    if idx<0: raise RuntimeError(f'No pude encontrar metodo {name}')
    brace=text.find('{',idx); depth=0
    for pos in range(brace,len(text)):
        if text[pos]=='{': depth+=1
        elif text[pos]=='}':
            depth-=1
            if depth==0: return text[:idx]+replacement.strip('\n')+text[pos+1:]
    raise RuntimeError(f'No pude cerrar metodo {name}')
def ensure_helpers(text):
    if 'private isUrlIcon(' in text: return text
    idx=text.find('  private parseWkt(')
    if idx<0: idx=text.rfind('\n}')
    return text[:idx]+HELPERS+'\n'+text[idx:]
def main():
    ap=argparse.ArgumentParser(); ap.add_argument('--dry-run',action='store_true'); args=ap.parse_args()
    root=Path.cwd()
    if not (root/'package.json').exists(): raise SystemExit('Ejecuta desde la raiz de klaxmap')
    d=root/'src/app/features/mapa/embed/pages/mapa-embed-viewer'
    ts=d/'mapa-embed-viewer.component.ts'; html=d/'mapa-embed-viewer.component.html'; scss=d/'mapa-embed-viewer.component.scss'
    for p in (ts,html,scss):
        if not p.exists(): raise SystemExit(f'No existe {p}')
    if args.dry_run:
        print('[dry-run] escribir',html); print('[dry-run] escribir',scss); print('[dry-run] parchear',ts); return
    backup(html); html.write_text(HTML.strip()+'\n',encoding='utf-8'); print('ok:',html)
    backup(scss); scss.write_text(SCSS.strip()+'\n',encoding='utf-8'); print('ok:',scss)
    text=ts.read_text(encoding='utf-8')
    text=replace_method(text,'createElementIcon',METHOD)
    text=ensure_helpers(text)
    text=text.replace("size: Math.max(16, Math.min(42, Number(item.tamanoIcono ?? 26) + (selected ? 5 : 0))),","size: Math.max(10, Math.min(34, Number(item.tamanoIcono ?? 22) + (selected ? 3 : 0))),")
    backup(ts); ts.write_text(text,encoding='utf-8'); print('ok:',ts)
    print('\nListo. Ejecuta: npm run build')
if __name__=='__main__': main()
